from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_login import current_user, login_required

app = Flask(__name__)
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    username = db.Column(db.String(80), unique=True, nullable=False)
    account_type = db.Column(db.String(50), nullable=False)
    credits = db.Column(db.Integer, nullable=False)
    referral_code = db.Column(db.String(50), nullable=True)
    verified_status = db.Column(db.Boolean, default=False)

@app.route('/update_profile', methods=['PATCH'])
@login_required
def update_profile():
    data = request.json
    allowed_fields = ['email', 'username', 'account_type', 'credits', 'referral_code', 'verified_status']
    
    for field in allowed_fields:
        if field in data:
            if field == 'email' and not current_user.has_permission('update_email'):
                return jsonify({'error': 'Unauthorized to update email'}), 403
            if field == 'username' and not current_user.has_permission('update_username'):
                return jsonify({'error': 'Unauthorized to update username'}), 403
            if field == 'account_type' and not current_user.has_permission('update_account_type'):
                return jsonify({'error': 'Unauthorized to update account type'}), 403
            if field == 'credits' and not current_user.has_permission('update_credits'):
                return jsonify({'error': 'Unauthorized to update credits'}), 403
            if field == 'referral_code' and not current_user.has_permission('update_referral_code'):
                return jsonify({'error': 'Unauthorized to update referral code'}), 403
            if field == 'verified_status' and not current_user.has_permission('update_verified_status'):
                return jsonify({'error': 'Unauthorized to update verified status'}), 403
            
            setattr(current_user, field, data[field])
    
    db.session.commit()
    return jsonify({'message': 'Profile updated successfully'}), 200

